import{_ as e,o as s,c as t,a4 as n}from"./chunks/framework.BDOgl-CJ.js";const g=JSON.parse('{"title":"Sigmoid 函数","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/sigmoid.md","filePath":"ai-learning-notes/sigmoid.md","lastUpdated":1783493313000}'),i={name:"ai-learning-notes/sigmoid.md"};function l(o,a,r,d,p,h){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="sigmoid-函数" tabindex="-1">Sigmoid 函数 <a class="header-anchor" href="#sigmoid-函数" aria-label="Permalink to &quot;Sigmoid 函数&quot;">​</a></h1><p>神经网络激活函数之一，3Blue1Brown 课程中用于解释神经元工作原理。</p><hr><h2 id="数学定义" tabindex="-1">数学定义 <a class="header-anchor" href="#数学定义" aria-label="Permalink to &quot;数学定义&quot;">​</a></h2><p>$$ \\sigma(x) = \\frac{1}{1 + e^{-x}} $$</p><p>其中 e ≈ 2.718（自然常数）。</p><hr><h2 id="一句话理解" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解" aria-label="Permalink to &quot;一句话理解&quot;">​</a></h2><p><strong>把任意实数「挤压」到 0 到 1 之间。</strong></p><hr><h2 id="为什么是-e-而不是别的底数" tabindex="-1">为什么是 e 而不是别的底数？ <a class="header-anchor" href="#为什么是-e-而不是别的底数" aria-label="Permalink to &quot;为什么是 e 而不是别的底数？&quot;">​</a></h2><p>你可能想过：用 2^(-x) 或 10^(-x) 不也能把数压到 0~1 吗？为什么一定是 e？</p><h3 id="数学起源-logistic-regression-的推导" tabindex="-1">数学起源：logistic regression 的推导 <a class="header-anchor" href="#数学起源-logistic-regression-的推导" aria-label="Permalink to &quot;数学起源：logistic regression 的推导&quot;">​</a></h3><p>sigmoid 函数不是为神经网络发明的，它来自统计学中的 <strong>逻辑斯蒂回归（Logistic Regression）</strong>。</p><p>出发点是把「几率（odds）」取对数，建立线性关系：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         P                          P</span></span>
<span class="line"><span>odds = ─────        ln(odds) = ln(───────) = w₁x₁ + w₂x₂ + ... + b</span></span>
<span class="line"><span>        1-P                        1-P</span></span></code></pre></div><p>注意左边取的是 <strong>ln（自然对数，底数为 e）</strong>，不是 log₁₀ 或 log₂。把上式反解出 P：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  P</span></span>
<span class="line"><span>─────── = e^(w₁x₁ + ... + b)</span></span>
<span class="line"><span> 1 - P</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        e^(w₁x₁+...+b)          1</span></span>
<span class="line"><span>→ P = ───────────────── = ──────────────────</span></span>
<span class="line"><span>      1 + e^(w₁x₁+...+b)   1 + e^-(w₁x₁+...+b)</span></span></code></pre></div><p><strong>e 是被推导出来的，不是被选出来的。</strong></p><h3 id="工程理由-导数形式最简洁" tabindex="-1">工程理由：导数形式最简洁 <a class="header-anchor" href="#工程理由-导数形式最简洁" aria-label="Permalink to &quot;工程理由：导数形式最简洁&quot;">​</a></h3><p>对比不同底数：</p><table tabindex="0"><thead><tr><th>函数</th><th>导数</th></tr></thead><tbody><tr><td>1/(1+e⁻ˣ)</td><td>σ(x)·(1-σ(x)) ← <strong>一步乘法，完事</strong></td></tr><tr><td>1/(1+2⁻ˣ)</td><td>σ(x)·(1-σ(x))·ln(2)</td></tr><tr><td>1/(1+10⁻ˣ)</td><td>σ(x)·(1-σ(x))·ln(10)</td></tr></tbody></table><p>sigmoid 的导数值可以直接用函数值自身表示——正向传播时 σ(x) 已经算出来了，反向传播直接拿来乘，不需要重新算指数。</p><p>深层网络每层都要算导数，多了些常数因子虽然不影响结果正确性，但 e 的版本在计算上和数学表达上都最干净。</p><h3 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h3><blockquote><p>不是刻意选了 e，而是从 ln 的自然推导中，e 是那个「恰好」让函数和它的导数长得最像的底数。</p></blockquote><hr><h2 id="输入-→-输出映射" tabindex="-1">输入 → 输出映射 <a class="header-anchor" href="#输入-→-输出映射" aria-label="Permalink to &quot;输入 → 输出映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>输入 x</th><th>输出 σ(x)</th></tr></thead><tbody><tr><td>x → +∞</td><td>趋近于 1</td></tr><tr><td>x = 0</td><td>0.5</td></tr><tr><td>x → -∞</td><td>趋近于 0</td></tr></tbody></table><p>形状是一条 <strong>S 形曲线</strong>，中间陡峭、两端逐渐平缓（饱和）。</p><hr><h2 id="在神经网络中的作用" tabindex="-1">在神经网络中的作用 <a class="header-anchor" href="#在神经网络中的作用" aria-label="Permalink to &quot;在神经网络中的作用&quot;">​</a></h2><p>一个神经元的前向传播：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>加权和 = w₁x₁ + w₂x₂ + ... + b   ← 任意实数，可能是 -1000 或 +500</span></span>
<span class="line"><span>输出   = σ(加权和)               ← 压缩到 (0, 1)</span></span></code></pre></div><p>sigmoid 把无界的加权和映射为一个 (0,1) 之间的值，可以被解释为：</p><ul><li>该神经元的「激活程度」</li><li>一个类似于「概率」的输出（接近 1 = 强激活，接近 0 = 抑制）</li></ul><hr><h2 id="为什么-3blue1brown-用它来讲" tabindex="-1">为什么 3Blue1Brown 用它来讲 <a class="header-anchor" href="#为什么-3blue1brown-用它来讲" aria-label="Permalink to &quot;为什么 3Blue1Brown 用它来讲&quot;">​</a></h2><ul><li>曲线光滑连续，数学性质良好</li><li>S 形符合人对「开关/激活」的直觉</li><li>导数有漂亮的形式：σ&#39;(x) = σ(x) · (1 - σ(x))，方便手算反向传播</li><li>是理解神经网络逻辑的最佳入口</li></ul><hr><h2 id="为什么现代深度学习不用了" tabindex="-1">为什么现代深度学习不用了 <a class="header-anchor" href="#为什么现代深度学习不用了" aria-label="Permalink to &quot;为什么现代深度学习不用了&quot;">​</a></h2><p>两个致命缺陷：</p><h3 id="_1-梯度消失-vanishing-gradient" tabindex="-1">1. 梯度消失（Vanishing Gradient） <a class="header-anchor" href="#_1-梯度消失-vanishing-gradient" aria-label="Permalink to &quot;1. 梯度消失（Vanishing Gradient）&quot;">​</a></h3><p>两端饱和区导数趋近于 0：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x → +∞：σ&#39;(x) ≈ 0</span></span>
<span class="line"><span>x → -∞：σ&#39;(x) ≈ 0</span></span></code></pre></div><p>深层网络中，反向传播时梯度连乘，经过多层 sigmoid 后梯度指数级衰减 → 前面的层几乎学不到东西。</p><h3 id="_2-非零中心-not-zero-centered" tabindex="-1">2. 非零中心（Not Zero-Centered） <a class="header-anchor" href="#_2-非零中心-not-zero-centered" aria-label="Permalink to &quot;2. 非零中心（Not Zero-Centered）&quot;">​</a></h3><p>sigmoid 输出恒为正（0~1），下一层所有输入的符号相同，导致梯度更新时产生 zigzag 震荡，收敛变慢。</p><hr><h2 id="现代替代方案-relu" tabindex="-1">现代替代方案：ReLU <a class="header-anchor" href="#现代替代方案-relu" aria-label="Permalink to &quot;现代替代方案：ReLU&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ReLU(x) = max(0, x)</span></span></code></pre></div><ul><li>正区间导数恒为 1 → 不衰减 → 深层网络也能训练</li><li>计算极快（就是取最大值）</li><li>实际效果远超 sigmoid</li></ul><p>但 sigmoid 仍然是理解激活函数概念的最好起点。</p><hr><h2 id="相关笔记" tabindex="-1">相关笔记 <a class="header-anchor" href="#相关笔记" aria-label="Permalink to &quot;相关笔记&quot;">​</a></h2><ul><li><a href="./backpropagation">反向传播：模型是怎么学习的</a></li><li><a href="./mean-variance-std">均值、方差、标准差</a></li><li><a href="./transformer-encoder-decoder">Transformer 编码器与解码器</a></li></ul>`,56)])])}const b=e(i,[["render",l]]);export{g as __pageData,b as default};
